@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;0,800;1,400;1,500&family=Outfit:wght@300;400;500;600;700&family=Inter:wght@300;400;500;600;700&family=Lora:ital,wght@0,400;0,500;0,600;0,700;1,400;1,500&family=Nunito:ital,wght@0,200..1000;1,200..1000&family=Comfortaa:wght@300..700&family=Lexend+Deca:wght@100..900&family=Patrick+Hand&family=Shadows+Into+Light&family=Sniglet:wght@400;800&display=swap');

:root {
  font-family: "Outfit", sans-serif;
  font-optical-sizing: auto;
  line-height: 1.5;
  font-weight: 400;

  font-synthesis: none;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;

  /* ── Semantic color tokens ── */
  --bg-primary: #FAF9F6;
  --bg-secondary: #F3F1ED;
  --bg-hover: #EDEAE5;
  --bg-elevated: #FFFFFF;
  --bg-backdrop: rgba(250,249,246,0.75);
  --bg-backdrop-heavy: rgba(250,249,246,0.85);
  --bg-overlay: rgba(250,249,246,0.3);
  --bg-pill: rgba(120,100,80,0.06);
  --bg-glass: rgba(255,255,255,0.55);
  --bg-glass-border: rgba(200,180,150,0.2);

  --text-primary: #1A1612;
  --text-heading: #12100D;
  --text-secondary: #6B6560;
  --text-body: #8A8480;
  --text-muted: #A8A29E;
  --text-faint: #C0BBB5;
  --text-separator: #D9D4CE;

  --border-light: rgba(120,100,80,0.12);
  --border-card: rgba(120,100,80,0.08);

  --shadow-card: 0 1px 4px rgba(80,60,40,0.06), 0 4px 16px rgba(80,60,40,0.04);
  --shadow-modal: 0 8px 32px rgba(80,60,40,0.12);

  --accent-purple: #C4943E;
  --accent-dark: #1A1612;
  --accent-dark-hover: #3A3530;

  --icon-default: #8A8480;
  --icon-view: rgba(26,22,18,0.25);
  --icon-view-count: rgba(26,22,18,0.55);

  --font-serif: "Lora", Georgia, "Times New Roman", serif;
  --font-ui: "Outfit", sans-serif;

  --bg-card: #FEFEFE;
  --accent-sage: #8A9E7A;
  --accent-amber: #D4A853;

  --color-danger: #DC2626;
  --color-danger-bg: rgba(220, 38, 38, 0.08);
  --color-success: #16A34A;
  --color-success-bg: rgba(22, 163, 74, 0.08);

  --shadow-card-sm: 0 1px 2px rgba(80,60,40,0.05);
  --shadow-dropdown: 0 4px 16px rgba(80,60,40,0.1), 0 0 0 1px rgba(120,100,80,0.06);

  --bg-selection: rgba(212,168,83,0.08);
  --bg-selection-active: rgba(212,168,83,0.15);

  --loader-color: #C4943E;

  /* global */
  color-scheme: light;
  color: var(--text-primary);
  background-color: var(--bg-primary);
}

[data-theme="dark"] {
  --bg-primary: #1A1916;
  --bg-secondary: #222220;
  --bg-hover: #2C2C2A;
  --bg-elevated: #262624;
  --bg-backdrop: rgba(26,25,22,0.85);
  --bg-backdrop-heavy: rgba(26,25,22,0.92);
  --bg-overlay: rgba(0,0,0,0.4);
  --bg-pill: rgba(255,240,210,0.06);

  --text-primary: #F0EBE3;
  --text-heading: #F5F0E8;
  --text-secondary: #B0A89E;
  --text-body: #908880;
  --text-muted: #6B6560;
  --text-faint: #504A45;
  --text-separator: #3A3632;

  --border-light: rgba(255,240,210,0.08);
  --border-card: rgba(255,240,210,0.06);

  --shadow-card: 0 2px 8px rgba(0,0,0,0.2);
  --shadow-modal: 0 8px 32px rgba(0,0,0,0.35);

  --accent-purple: #D4A853;
  --accent-dark: #F0EBE3;
  --accent-dark-hover: #C8C0B5;

  --bg-glass: rgba(255,255,255,0.07);
  --bg-glass-border: rgba(255,240,210,0.10);

  --icon-default: #908880;
  --icon-view: rgba(240,235,227,0.25);
  --icon-view-count: rgba(240,235,227,0.55);

  --font-serif: "Lora", Georgia, "Times New Roman", serif;
  --font-ui: "Outfit", sans-serif;

  --bg-card: #1E1E1C;
  --accent-sage: #9AB08A;
  --accent-amber: #E0BA6A;

  --color-danger: #EF4444;
  --color-danger-bg: rgba(239, 68, 68, 0.12);
  --color-success: #22C55E;
  --color-success-bg: rgba(34, 197, 94, 0.12);

  --shadow-card-sm: 0 1px 3px rgba(0,0,0,0.15);
  --shadow-dropdown: 0 4px 16px rgba(0,0,0,0.25), 0 0 0 1px rgba(255,240,210,0.06);

  --bg-selection: rgba(212,168,83,0.1);
  --bg-selection-active: rgba(212,168,83,0.18);

  --loader-color: #D4A853;

  color-scheme: dark;
  color: var(--text-primary);
  background-color: var(--bg-primary);
}

a {
  font-weight: 500;
  color: #C4943E;
  text-decoration: inherit;
}
a:hover {
  color: #B8862D;
}

body {
  margin: 0;
  display: flex;
  place-items: center;
  min-width: 320px;
  min-height: 100vh;
  overflow-x: hidden;
  background-color: var(--bg-primary);
  color: var(--text-primary);
  transition: background-color 0.2s ease, color 0.2s ease;
}

