 32→const normalizeInteractionFlag = (value) => {
 33→    if(typeof value === 'boolean') return value;
 34→    if(typeof value === 'string'){
 35→        const normalized = value.trim().toLowerCase();
 36→        if(normalized === 'true') return true;
 37→        if(normalized === 'false') return false;
 38→    }
 39→    if(typeof value === 'number'){
 40→        return value === 1;
 41→    }
 42→    return Boolean(value);
 43→};
 44→
 45→const normalizeCount = (value) => {
 46→    const number = Number(value);
 47→    if(!Number.isFinite(number) || number < 0){
 48→        return 0;
 49→    }
 50→    return number;
 51→};
 52→
 53→const getNextToggleCount = (isActive, currentCount) => {
 54→    return isActive
 55→        ? Math.max(0, currentCount - 1)
 56→        : currentCount + 1;
 57→};
