 13→const incrementJournalCommentCount = (old, postId) => {
 14→    if (!old || !Array.isArray(old.pages)) return old;
 15→
 16→    return {
 17→        ...old,
 18→        pages: old.pages.map((page) => ({
 19→            ...page,
