        }

        return [homeLink, exploreLink,
            {
                path: '/profile',
                label: 'Profile', action: ()=> navigatePath('/profile'),
                icon:
                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="#000000ff">
                    <g id="style=fill">
