            ) : (
            <>
            {!isSearchMode && session && (
                <DashboardBriefing onWriteResponse={(prompt) => {
                    if (handleOpenTextEditor) {
                        handleOpenTextEditor({ promptId: prompt.id, promptText: prompt.prompt_text });
